UPDATE comment
SET reply_count = reply_count + 1
WHERE id = #{rootId}

update comment
SET status = '0'
WHERE id = #{id}

mapper.select:
SELECT *
FROM comment
WHERE root_id = #{rootId}
AND parent_id != 0
AND status = '1'

    AND id > #{lastId}

ORDER BY id ASC
LIMIT #{size}

SELECT rootId FROM ( -- 1️⃣ 正常存在的一级评论 SELECT id AS rootId FROM comment WHERE article_id = #{articleId} AND parent_id = 0 AND status = '1'
AND id < #{lastId}
UNION ALL
-- 2️⃣ 被删除但仍有子评论的 root SELECT DISTINCT root_id AS rootId FROM comment WHERE article_id = #{articleId} AND root_id != 0 AND status = '1'
AND root_id < #{lastId}
) t GROUP BY rootId ORDER BY rootId DESC LIMIT #{size}
